import React, { useState, useEffect } from 'react';

interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

interface CountdownProps {
  day: string;
}

const Count: React.FC<CountdownProps> = ({ day }) => {
  const [timeLeft, setTimeLeft] = useState<TimeLeft>(calculateTimeLeft(day));

  function calculateTimeLeft(day: string): TimeLeft {
    const difference = new Date(day).getTime() - new Date().getTime();

    if (difference <= 0) {
      return {
        days: 0,
        hours: 0,
        minutes: 0,
        seconds: 0,
      };
    }

    const days = Math.floor(difference / (1000 * 60 * 60 * 24));
    const hours = Math.floor(
      (difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)
    );
    const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
    const seconds = Math.floor((difference % (1000 * 60)) / 1000);

    return { days, hours, minutes, seconds };
  }

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(calculateTimeLeft(day));
    }, 1000);

    return () => clearInterval(timer);
  }, [day]);

  return (
    <div className="w-full h-full bg-[#656c64] flex items-center justify-center gap-5 py-28">
      <div className="flex items-center gap-5">
        <div className="flex flex-col justify-center items-start gap-5">
          <div className="w-24 h-24 text-3xl text-[#656c64] shadow-md bg-white flex items-center justify-center rounded-lg">
            {timeLeft?.days}
          </div>
          <p className="text-white text-xl">Días</p>
        </div>
        <p className="text-white text-xl font-bold">:</p>
      </div>
      <div className="flex flex-col items-center gap-5">
        <div className="w-24 h-24 text-3xl text-[#656c64] shadow-md bg-white flex items-center justify-center rounded-lg">
          {timeLeft.hours}
        </div>
        <p className="text-white text-xl">Horas</p>
      </div>
      <p className="text-white text-xl font-bold">:</p>

      <div className="flex flex-col items-center gap-5">
        <div className="w-24 h-24 text-3xl text-[#656c64] shadow-md bg-white flex items-center justify-center rounded-lg">
          {timeLeft?.minutes}
        </div>
        <p className="text-white text-xl">Minutos</p>
      </div>
      <p className="text-white text-xl font-bold">:</p>
      <div className="flex flex-col items-center gap-5">
        <div className="w-24 h-24 text-3xl text-[#656c64] shadow-md bg-white flex items-center justify-center rounded-lg">
          {timeLeft.seconds}
        </div>
        <p className="text-white text-xl">Segundos</p>
      </div>
    </div>
  );
};

export default Count;
